def should_process_file(file_path):
    """Check if file should be processed (CSV or Excel) - case insensitive"""
    extensions = ['.csv', '.xlsx', '.xls']
    return any(file_path.lower().endswith(ext) for ext in extensions)

def get_file_type(file_path):
    """Determine if file is CSV or Excel"""
    if file_path.lower().endswith(('.xlsx', '.xls')):
        return 'excel'
    elif file_path.lower().endswith('.csv'):
        return 'csv'
    return None

def is_zip_file(file_path):
    """Check if file is a zip file"""
    return file_path.lower().endswith('.zip')

def print_quarantine_summary(moved_files):
    """
    Print summary showing ONLY the 6 essential error types
    """
    quarantined = moved_files.get('quarantine', [])

    if len(quarantined) == 0:
        print("\n✅ No files quarantined")
        return

    print("\n" + "=" * 70)
    print("QUARANTINE SUMMARY - ESSENTIAL ERRORS ONLY")
    print("=" * 70)

    # Count each error type
    error_counts = {
        'ZIP_CORRUPTED': [],
        'ZIP_PASSWORD_PROTECTED': [],
        'EXCEL_CORRUPTED': [],
        'EXCEL_EMPTY': [],
        'CSV_CORRUPTED': [],
        'CSV_EMPTY': []
    }

    for file_path in quarantined:
        filename = os.path.basename(file_path)

        # Extract error code from filename
        for error_code in error_counts.keys():
            if error_code in filename:
                error_counts[error_code].append(filename)
                break

    # Print each category
    if error_counts['ZIP_CORRUPTED']:
        print(f"\n💥 CORRUPTED ZIP FILES ({len(error_counts['ZIP_CORRUPTED'])}):")
        for f in error_counts['ZIP_CORRUPTED'][:10]:
            print(f"   • {f}")
        if len(error_counts['ZIP_CORRUPTED']) > 10:
            print(f"   ... and {len(error_counts['ZIP_CORRUPTED']) - 10} more")

    if error_counts['ZIP_PASSWORD_PROTECTED']:
        print(f"\n🔒 PASSWORD PROTECTED ZIP FILES ({len(error_counts['ZIP_PASSWORD_PROTECTED'])}):")
        for f in error_counts['ZIP_PASSWORD_PROTECTED'][:10]:
            print(f"   • {f}")
        if len(error_counts['ZIP_PASSWORD_PROTECTED']) > 10:
            print(f"   ... and {len(error_counts['ZIP_PASSWORD_PROTECTED']) - 10} more")

    if error_counts['EXCEL_CORRUPTED']:
        print(f"\n💥 CORRUPTED EXCEL FILES ({len(error_counts['EXCEL_CORRUPTED'])}):")
        for f in error_counts['EXCEL_CORRUPTED'][:10]:
            print(f"   • {f}")
        if len(error_counts['EXCEL_CORRUPTED']) > 10:
            print(f"   ... and {len(error_counts['EXCEL_CORRUPTED']) - 10} more")

    if error_counts['EXCEL_EMPTY']:
        print(f"\n📭 EMPTY EXCEL FILES ({len(error_counts['EXCEL_EMPTY'])}):")
        for f in error_counts['EXCEL_EMPTY'][:10]:
            print(f"   • {f}")
        if len(error_counts['EXCEL_EMPTY']) > 10:
            print(f"   ... and {len(error_counts['EXCEL_EMPTY']) - 10} more")

    if error_counts['CSV_CORRUPTED']:
        print(f"\n💥 CORRUPTED CSV FILES ({len(error_counts['CSV_CORRUPTED'])}):")
        for f in error_counts['CSV_CORRUPTED'][:10]:
            print(f"   • {f}")
        if len(error_counts['CSV_CORRUPTED']) > 10:
            print(f"   ... and {len(error_counts['CSV_CORRUPTED']) - 10} more")

    if error_counts['CSV_EMPTY']:
        print(f"\n📭 EMPTY CSV FILES ({len(error_counts['CSV_EMPTY'])}):")
        for f in error_counts['CSV_EMPTY'][:10]:
            print(f"   • {f}")
        if len(error_counts['CSV_EMPTY']) > 10:
            print(f"   ... and {len(error_counts['CSV_EMPTY']) - 10} more")

    print("\n" + "=" * 70)
    print(f"Total quarantined: {len(quarantined)} files")
    print("=" * 70)

def verify_file_processed(file_path, moved_files):
    """Verify if a file was successfully processed"""
    # Check if the file path or a derivative is in the success lists
    file_name = os.path.basename(file_path)

    # Check in data_success
    for success_path in moved_files.get('data_success', []):
        if file_name in success_path:
            return True

    # Check in other success categories
    for category in ['metadata_success', 'empty', 'quarantine', 'overseas']:
        for success_path in moved_files.get(category, []):
            if file_name in success_path:
                return True

    return False  # Use False

def read_processed_files_log(storage_account):
    """Read the log of previously processed files"""
    log_file_path = f"abfss://{processing_container}@{storage_account}.dfs.core.windows.net/L0_process_log/processed_files_log.json"

    print("\n" + "=" * 70)
    print("READING PROCESSED FILES LOG")
    print("=" * 70)

    if not mssparkutils.fs.exists(log_file_path):
        print("ℹ️  No existing processed files log found")
        print("   All files will be processed as new")
        return set()

    try:
        # Read using Spark
        text_df = spark.read.text(log_file_path)
        log_content = "\n".join([row.value for row in text_df.collect()])

        # Parse JSON - handle both list and object formats
        log_data = json.loads(log_content)

        processed_files = set()

        # Handle different log formats
        if isinstance(log_data, list):
            # List format: [{"file": "path"}, ...]
            for entry in log_data:
                if isinstance(entry, dict) and "file" in entry:
                    file_path = entry["file"]
                    processed_files.add(file_path.lower())
                    processed_files.add(normalize_file_path(file_path))
        elif isinstance(log_data, dict) and "processed_files" in log_data:
            # Object format: {"processed_files": [...]}
            for entry in log_data["processed_files"]:
                if isinstance(entry, dict):
                    file_path = entry.get("file_path", entry.get("file", ""))
                    if file_path:
                        processed_files.add(file_path.lower())
                        processed_files.add(normalize_file_path(file_path))

        print(f"✅ Successfully loaded {len(processed_files)} processed file entries")

        # Show sample
        sample = list(processed_files)[:3]
        if sample:
            print("\n📋 Sample entries:")
            for i, fp in enumerate(sample, 1):
                print(f"   {i}. {fp[:80]}...")

        return processed_files

    except Exception as e:
        print(f"❌ ERROR reading log: {str(e)}")
        import traceback
        print(traceback.format_exc())
        return set()
